arguments.file_text:
namespace sv_2ee9005537f84952a987c4bd0b3b1670.Models;

public record Channel(int Id, string Name, string Description, int UnreadCount);

public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);

public record Reaction(string Emoji, List<string> Users);

public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

.chat-app-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    margin: 0;
    padding: 0;
}

@using sv_2ee9005537f84952a987c4bd0b3b1670.Models

<div class="message-input">
    <textarea @bind="Text" @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="send-btn" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string Text { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await Send();
        }
    }

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var message = Text.Trim();
        Text = "";
        await OnSend.InvokeAsync(message);
    }
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 14px;
    font-family: inherit;
    outline: none;
    transition: border-color 0.2s;
}

.message-input textarea:focus {
    border-color: #5865f2;
}

.send-btn {
    padding: 8px 20px;
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #4752c4;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_2ee9005537f84952a987c4bd0b3b1670.Models

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <div class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                 @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                <div class="channel-desc">@TruncateDescription(channel.Description)</div>
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 50 ? desc[..47] + "..." : desc;
    }
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background: #2b2d31;
    color: #b5bac1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #1e1f22;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
}

.channel-item {
    padding: 8px 12px;
    border-radius: 6px;
    cursor: pointer;
    margin-bottom: 2px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #35373c;
    color: #dbdee1;
}

.channel-item.active {
    background: #404249;
    color: #fff;
}

.channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-size: 15px;
    font-weight: 500;
}

.channel-item.active .channel-name {
    font-weight: 700;
}

.unread-badge {
    background: #f23f43;
    color: #fff;
    font-size: 11px;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-desc {
    font-size: 12px;
    color: #8a8e94;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@using sv_2ee9005537f84952a987c4bd0b3b1670.Models

<div class="message-item"
     @onmouseenter="() => showActions = true"
     @onmouseleave="HideActions">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    <span>@reaction.Emoji</span>
                    <span class="reaction-count">@reaction.Users.Count</span>
                </button>
            }
        </div>
    }

    @if (IsThreadStarter && ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😊 React
            </button>
        </div>

        @if (showEmojiPicker)
        {
            <div class="emoji-picker">
                @foreach (var emoji in CommonEmojis)
                {
                    <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public bool IsThreadStarter { get; set; }
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void HideActions()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    public static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
