@using sv_2ee9005537f84952a987c4bd0b3b1670.Models

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <div class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                 @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                <div class="channel-desc">@TruncateDescription(channel.Description)</div>
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 50 ? desc[..47] + "..." : desc;
    }
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background: #2b2d31;
    color: #b5bac1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #1e1f22;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
}

.channel-item {
    padding: 8px 12px;
    border-radius: 6px;
    cursor: pointer;
    margin-bottom: 2px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #35373c;
    color: #dbdee1;
}

.channel-item.active {
    background: #404249;
    color: #fff;
}

.channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-size: 15px;
    font-weight: 500;
}

.channel-item.active .channel-name {
    font-weight: 700;
}

.unread-badge {
    background: #f23f43;
    color: #fff;
    font-size: 11px;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-desc {
    font-size: 12px;
    color: #8a8e94;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

