@using sv_2ee9005537f84952a987c4bd0b3b1670.Models

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="message-header">
                <span class="author">@RootMessage.Author</span>
                <span class="timestamp">@MessageItem.FormatRelativeTime(RootMessage.SentAt)</span>
            </div>
            <div class="message-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var msg in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="author">@msg.Author</span>
                        <span class="timestamp">@MessageItem.FormatRelativeTime(msg.SentAt)</span>
                    </div>
                    <div class="message-content">@msg.Content</div>
                </div>
            }
        </div>
    }

    <MessageInput Placeholder="Reply in thread..." ButtonLabel="Reply" OnSend="OnReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
}

.thread-panel {
    height: 100%;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #f9fafb;
}

.thread-header h4 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
    color: #111;
}

.close-btn {
    background: none;
    border: none;
    font-size: 18px;
    color: #666;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background 0.15s;
}

.close-btn:hover {
    background: #e0e0e0;
    color: #111;
}

.thread-root-message {
    padding: 12px 16px;
    background: #f2f3f5;
    border-bottom: 1px solid #e0e0e0;
}

.thread-root-message .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 4px;
}

.thread-root-message .author {
    font-weight: 600;
    font-size: 14px;
    color: #111;
}

.thread-root-message .timestamp {
    font-size: 12px;
    color: #8a8e94;
}

.thread-root-message .message-content {
    font-size: 14px;
    color: #2e3035;
    line-height: 1.4;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 12px;
    color: #8a8e94;
    border-bottom: 1px solid #e0e0e0;
    background: #fafafa;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 8px 16px;
    border-radius: 4px;
}

.thread-reply:hover {
    background: #f2f3f5;
}

.thread-reply .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.thread-reply .author {
    font-weight: 600;
    font-size: 14px;
    color: #111;
}

.thread-reply .timestamp {
    font-size: 12px;
    color: #8a8e94;
}

.thread-reply .message-content {
    font-size: 14px;
    color: #2e3035;
    line-height: 1.4;
}

