+        }
+
+        messages.InsertRange(0, older);
+        await BuildThreadSummaries();
+
+        isLoadingMore = false;
+        StateHasChanged();
+
+        // Preserve scroll position after prepending messages
+        await Task.Yield();
+        if (jsModule is not null)
+        {
+            await jsModule.InvokeVoidAsync("preserveScrollPosition", messageListRef, previousScrollHeight);
+        }
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (selectedChannel is null) return;
+
+        var newMessage = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
+        messages.Add(newMessage);
+        StateHasChanged();
+
+        await Task.Yield();
+        if (jsModule is not null)
+        {
+            await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
+        }
+    }
+
+    private async Task OpenThread(int messageId)
+    {
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
+        if (threadRootMessage is null) return;
+
+        threadMessages = await ChatService.GetThreadAsync(messageId);
+        isThreadOpen = true;
+    }
+
+    private void CloseThreadSync()
+    {
+        isThreadOpen = false;
+        threadRootMessage = null;
+        threadMessages.Clear();
+    }
+
+    private Task CloseThread()
+    {
+        CloseThreadSync();
+        return Task.CompletedTask;
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (threadRootMessage is null || selectedChannel is null) return;
+
+        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
+        threadMessages.Add(reply);
+
+        // Update thread summary in main view
+        if (threadSummaries.ContainsKey(threadRootMessage.Id))
+        {
+            var existing = threadSummaries[threadRootMessage.Id];
+            threadSummaries[threadRootMessage.Id] = existing with
+            {
+                ReplyCount = existing.ReplyCount + 1,
+                LastReplyAt = reply.SentAt
+            };
+        }
+        else
+        {
+            threadSummaries[threadRootMessage.Id] = new ThreadSummary(
+                threadRootMessage.Id, 1, reply.SentAt);
+        }
+    }
+
+    private async Task HandleReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+
+        // Refresh the message to get updated reactions
+        if (selectedChannel is not null)
+        {
+            var updated = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
+            messages = updated;
+        }
+    }
+
+    private async Task BuildThreadSummaries()
+    {
+        // Identify thread starters: messages that other messages reply to
+        var rootIds = messages
+            .Where(m => m.ReplyToId is not null)
+            .Select(m => m.ReplyToId!.Value)
+            .Distinct()
+            .ToHashSet();
+
+        // Also check messages with no ReplyToId that might be thread starters
+        foreach (var msg in messages.Where(m => m.ReplyToId is null))
+        {
+            try
+            {
+                var replies = await ChatService.GetThreadAsync(msg.Id);
+                if (replies.Count > 0)
+                {
+                    threadSummaries[msg.Id] = new ThreadSummary(
+                        msg.Id, replies.Count, replies.Max(r => r.SentAt));
+                }
+            }
+            catch
+            {
+                // Thread endpoint may return empty for non-thread messages
+            }
+        }
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        dotNetRef?.Dispose();
+        if (jsModule is not null)
+        {
+            await jsModule.DisposeAsync();
+        }
+    }
+}
+

toolArgs.file_text:
.chat-container {
    display: flex;
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

/* Sidebar: ~20% width */
.sidebar-panel {
    width: 260px;
    min-width: 220px;
    flex-shrink: 0;
}

/* Main panel: flexible width */
.main-panel {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
    overflow: hidden;
}

.main-panel.with-thread {
    /* When thread is open, main area shrinks */
}

/* Thread panel: ~25% width */
.thread-panel-container {
    width: 380px;
    min-width: 320px;
    flex-shrink: 0;
}

/* Channel header */
.channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

.channel-header h2 {
    margin: 0;
    font-size: 18px;
    font-weight: 700;
    color: #111;
}

.channel-header p {
    margin: 4px 0 0;
    font-size: 13px;
    color: #6d6f78;
}

/* Message list */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 13px;
    color: #8a8e94;
    font-style: italic;
}

.beginning-indicator {
    text-align: center;
    padding: 16px;
    font-size: 13px;
    color: #8a8e94;
    border-bottom: 1px solid #e0e0e0;
    margin-bottom: 8px;
}

/* Empty state */
.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #8a8e94;
    font-size: 16px;
}

